mapper.select:
SELECT a.id id, url, b.`name` name, count, `share`, state, app_show_falg appShowFalg, app_view_counts appViewCounts, a.creat_time creatTime FROM app_video as a LEFT JOIN app_user as b ON a.user_id = b.id where 1=1
AND state = #{state}
AND DATE_FORMAT(a.create_time,'%Y-%m-%d') = #{format}
AND url like CONCAT('%',#{url},'%')
ORDER BY a.creat_time DESC LIMIT #{pageOffset},20
